#!/bin/bash
set -e
echo "Searching for dashboard sub-components..."
find Beme-Frontend/src -name "DashboardHome.jsx" -o -name "DashboardChat.jsx" -o -name "DashboardOrders.jsx" 2>/dev/null | head -10

# Auto-detect the sub-components directory
SUB_DIR=$(find Beme-Frontend/src -name "DashboardHome.jsx" 2>/dev/null | head -1 | xargs dirname 2>/dev/null)

if [ -z "$SUB_DIR" ]; then
  echo "ERROR: Could not find sub-components. Check your folder structure."
  exit 1
fi

echo "Found sub-components at: $SUB_DIR"
echo "[Batch-replacing blue colors...]"
echo "" | base64 -d > /tmp/patch_seller.js
node /tmp/patch_seller.js "$SUB_DIR"
rm -f /tmp/patch_seller.js

cd Beme-Frontend && git add . && git commit -m "Seller dashboard sub-components: purple color replace" && git push
echo "Done!"
